import { Link, useNavigate } from "react-router-dom";
import {
  Compass,
  Users,
  Shield,
  ArrowRight,
  Star,
  MapPin,
  Clock,
  TrendingUp,
  ChevronRight,
  Mountain,
  Tent,
  Footprints,
  Quote,
  CheckCircle2,
} from "lucide-react";
import { useState, useEffect, useRef } from "react";
import { useLogoutHandler } from "../hooks/useLogoutHandler";
import LogoutModal from "../components/LogoutModal";
import { Header } from "../components/Header";
import { Footer } from "../components/Footer";

/* ───────────── Static Data ───────────── */

const destinations = [
  {
    title: "Annapurna Circuit",
    location: "Manang & Mustang",
    duration: "12-16 Days",
    difficulty: "Moderate",
    rating: 4.9,
    reviews: 342,
    image:
      "https://images.unsplash.com/photo-1585409677983-0f6c41ca9c3b?w=600&q=80",
    tag: "Most Popular",
  },
  {
    title: "Everest Base Camp",
    location: "Solukhumbu",
    duration: "14 Days",
    difficulty: "Challenging",
    rating: 4.8,
    reviews: 518,
    image:
      "https://images.unsplash.com/photo-1486911278844-a81c5267e227?w=600&q=80",
    tag: "Iconic",
  },
  {
    title: "Langtang Valley",
    location: "Rasuwa",
    duration: "7-10 Days",
    difficulty: "Easy-Moderate",
    rating: 4.7,
    reviews: 189,
    image:
      "https://images.unsplash.com/photo-1464822759023-fed622ff2c3b?w=600&q=80",
    tag: "Hidden Gem",
  },
  {
    title: "Upper Mustang",
    location: "Mustang",
    duration: "10-12 Days",
    difficulty: "Moderate",
    rating: 4.9,
    reviews: 127,
    image:
      "https://images.unsplash.com/photo-1544735716-392fe2489ffa?w=600&q=80",
    tag: "Off the Beaten Path",
  },
  {
    title: "Manaslu Circuit",
    location: "Gorkha",
    duration: "14-18 Days",
    difficulty: "Challenging",
    rating: 4.8,
