              to="/register"
              className="group inline-flex items-center justify-center gap-2 px-8 py-4 text-lg font-bold text-white rounded-xl shadow-xl shadow-brand-orange/30 hover:shadow-2xl hover:shadow-brand-orange/40 hover:scale-[1.02] transition-all duration-300"
              style={{
                background:
                  "linear-gradient(135deg, #F27A1A 0%, #FF9F43 100%)",
              }}
            >
              Create Free Account
              <ArrowRight className="h-5 w-5 group-hover:translate-x-1 transition-transform" />
            </Link>
            <Link
              to="/login"
              className="inline-flex items-center justify-center gap-2 px-8 py-4 text-lg font-semibold text-white border-2 border-white/20 rounded-xl hover:bg-white/10 transition-all duration-300"
            >
              Sign In
            </Link>
          </div>
        </div>
      </section>

      {/* ── Footer ── */}
      <Footer />

      {/* ── Logout Modal ── */}
      <LogoutModal
        isOpen={showLogoutModal}
        onConfirm={handleLogout}
        onCancel={handleStayLoggedIn}
      />
    </div>
  );
};

export default LandingPage;
